1	// Xianjun jiao. putaoshu@msn.com; xianjun.jiao@imec.be;
2	
3	`timescale 1 ns / 1 ps
4	
5	`include "xpu_pre_def.v"
6	
7	`ifdef XPU_ENABLE_DBG
8	`define DEBUG_PREFIX (*mark_debug="true",DONT_TOUCH="TRUE"*)
9	`else
10	`define DEBUG_PREFIX
11	`endif
12	
13		module pkt_filter_ctl #
14		(
15		)
16		(
17	        input wire clk,
18	        input wire rstn,
19	
20	        `DEBUG_PREFIX input wire [13:0] filter_cfg, //we don't support BSSID filter for now
21	        `DEBUG_PREFIX input wire [8:0] high_priority_discard_mask,
22	
23	        `DEBUG_PREFIX input wire [15:0] max_signal_len_th,
24	
25	        `DEBUG_PREFIX output wire block_rx_dma_to_ps,
26	        `DEBUG_PREFIX output reg  block_rx_dma_to_ps_valid,
27	        `DEBUG_PREFIX input wire [47:0] self_mac_addr,
28	        `DEBUG_PREFIX input wire [47:0] self_bssid,
29	        
30		    // Ports to phy_rx //
31		    input wire ht_unsupport,
32	
33	        `DEBUG_PREFIX input wire [1:0] FC_type,
34	        `DEBUG_PREFIX input wire [3:0] FC_subtype,
35	        `DEBUG_PREFIX input wire [1:0] FC_tofrom_ds,
36	        `DEBUG_PREFIX input wire FC_DI_valid,
37	        `DEBUG_PREFIX input wire [15:0] signal_len,
38	        `DEBUG_PREFIX input wire sig_valid,
39	
40	        `DEBUG_PREFIX input wire [47:0] addr1, //no matter to DS or from DS, addr1 is always used for incoming pkt addr filter
41	        `DEBUG_PREFIX input wire addr1_valid,
42	        `DEBUG_PREFIX input wire [47:0] addr2, //no matter to DS or from DS, addr2 is always the target addr we ACK to
43	        `DEBUG_PREFIX input wire addr2_valid,
44	        input wire [47:0] addr3,
45	        input wire addr3_valid
46		);
47	
48	    wire is_beacon;
49	    wire is_probereq;
50	    wire is_proberesp;
51	    wire is_ctrlwrapper;
52	    wire is_blkackreq;
53	    wire is_blkack;
54	    wire is_rts;
55	    wire is_ack;
56	    wire is_cfend;
57	    wire is_cfend_cfack;
58	    wire is_pspoll;
59	    wire except_pspoll;
60	    assign is_beacon      = (FC_type==0)&&(FC_subtype==8);
61	    assign is_probereq    = (FC_type==0)&&(FC_subtype==4);
62	    assign is_proberesp   = (FC_type==0)&&(FC_subtype==5);
63	    assign is_ctrlwrapper = (FC_type==1)&&(FC_subtype==7);
64	    assign is_blkackreq   = (FC_type==1)&&(FC_subtype==8);
65	    assign is_blkack      = (FC_type==1)&&(FC_subtype==9);
66	    assign is_pspoll      = (FC_type==1)&&(FC_subtype==10);
67	    assign except_pspoll  = (FC_type==1)&&(FC_subtype!=10);
68	    assign is_rts         = (FC_type==1)&&(FC_subtype==11);
69	    assign is_ack         = (FC_type==1)&&(FC_subtype==13);
70	    assign is_cfend       = (FC_type==1)&&(FC_subtype==14);
71	    assign is_cfend_cfack = (FC_type==1)&&(FC_subtype==15);
72	
73	    // from enum ieee80211_filter_flags in mac80211.h
74	    localparam [13:0]   FIF_ALLMULTI =           14'b00000000000010, //get all mac addr like 01:00:5E:xx:xx:xx and 33:33:xx:xx:xx:xx through to ARM
75	                        FIF_FCSFAIL =            14'b00000000000100, //not support
76	                        FIF_PLCPFAIL =           14'b00000000001000, //not support
77	                        FIF_BCN_PRBRESP_PROMISC= 14'b00000000010000, 
78	                        FIF_CONTROL =            14'b00000000100000,
79	                        FIF_OTHER_BSS =          14'b00000001000000, 
80	                        FIF_PSPOLL =             14'b00000010000000,
81	                        FIF_PROBE_REQ =          14'b00000100000000,
82	                        UNICAST_FOR_US =         14'b00001000000000,
83	                        BROADCAST_ALL_ONE =      14'b00010000000000,
84	                        BROADCAST_ALL_ZERO =     14'b00100000000000,
85	                        MY_BEACON          =     14'b01000000000000,
86	                        MONITOR_ALL =            14'b10000000000000;
87	
88	    localparam [2:0]   FILTER_IDLE     = 3'b000,
89	                       WAIT_FOR_ADDR1  = 3'b001,
90	                       WAIT_FOR_ADDR2  = 3'b010,
91	                       WAIT_FOR_ADDR3  = 3'b011,
92	                       FILTER_ACTION   = 3'b100,
93	                       ABNORMAL_STATE  = 3'b101;
94	
95	    `DEBUG_PREFIX reg [2:0] filter_state;
96	    `DEBUG_PREFIX reg [2:0] filter_state_pre;
97	
98	    `DEBUG_PREFIX reg [47:0] filter_bssid;
99	    `DEBUG_PREFIX reg filter_bssid_valid;
100	
101	    `DEBUG_PREFIX reg abnormal_flag;
102	
103	    // low 9 bits are the same as mac80211 definition. [9] - unicast, [10] - broadcast ALL 0xFF, [11] - broadcast ALL 0x00, [12] monitor ALL!
104	    `DEBUG_PREFIX reg [13:0] allow_rx_dma_to_ps_reg;
105	    `DEBUG_PREFIX reg [8:0] high_priority_discard_reg;
106	    `DEBUG_PREFIX wire block_rx_dma_to_ps_tmp;
107	    `DEBUG_PREFIX wire high_priority_discard_flag;
108	
109	    assign high_priority_discard_flag =((high_priority_discard_mask[0]&high_priority_discard_reg[0])|
110	                                        (high_priority_discard_mask[1]&high_priority_discard_reg[1])|
111	                                        (high_priority_discard_mask[2]&high_priority_discard_reg[2])|
112	                                        (high_priority_discard_mask[3]&high_priority_discard_reg[3])|
113	                                        (high_priority_discard_mask[4]&high_priority_discard_reg[4])|
114	                                        (high_priority_discard_mask[5]&high_priority_discard_reg[5])|
115	                                        (high_priority_discard_mask[6]&high_priority_discard_reg[6])|
116	                                        (high_priority_discard_mask[7]&high_priority_discard_reg[7])|
117	                                        (high_priority_discard_mask[8]&high_priority_discard_reg[8]));
118	
119	    assign block_rx_dma_to_ps_tmp =  ( ~(allow_rx_dma_to_ps_reg[0]|
120	                                     allow_rx_dma_to_ps_reg[1]|
121	                                     allow_rx_dma_to_ps_reg[2]|
122	                                     allow_rx_dma_to_ps_reg[3]|
123	                                     allow_rx_dma_to_ps_reg[4]|
124	                                     allow_rx_dma_to_ps_reg[5]|
125	                                     allow_rx_dma_to_ps_reg[6]|
126	                                     allow_rx_dma_to_ps_reg[7]|
127	                                     allow_rx_dma_to_ps_reg[8]|
128	                                     allow_rx_dma_to_ps_reg[9]|
129	                                    allow_rx_dma_to_ps_reg[10]|
130	                                    allow_rx_dma_to_ps_reg[11]|
131	                                    allow_rx_dma_to_ps_reg[12]|
132	                                    allow_rx_dma_to_ps_reg[13]) );
133	
134	    assign block_rx_dma_to_ps = (~((MONITOR_ALL&filter_cfg)!=0))&( block_rx_dma_to_ps_tmp|high_priority_discard_flag );
135	
136		always @(posedge clk)                                             
137	    begin
138	      if (rstn == 1'b0) 
139	        begin
140	          block_rx_dma_to_ps_valid <= 0;
141	          allow_rx_dma_to_ps_reg <= 0;
142	          high_priority_discard_reg<=0;
143	          filter_bssid <=0;
144	          filter_bssid_valid<=0;
145	          filter_state <= FILTER_IDLE;
146	          filter_state_pre <= FILTER_IDLE;
147	          abnormal_flag<=0;
148	        end                                                                   
149	      else                                                                    
150	        case (filter_state)
151	            FILTER_IDLE: 
152	                begin
153	                block_rx_dma_to_ps_valid <= 0;
154	                abnormal_flag<=0;
155	                filter_bssid <=filter_bssid;
156	                filter_bssid_valid<=filter_bssid_valid;
157	                if (sig_valid && ht_unsupport==0) 
158	                    begin
159	                    allow_rx_dma_to_ps_reg <= 0;
160	                    high_priority_discard_reg<=0;
161	                    filter_state_pre <= filter_state;
162	                    if (signal_len>=14 && signal_len<=max_signal_len_th) 
163	                        begin
164	                        filter_state <= WAIT_FOR_ADDR1;
165	                        end
166	                    else 
167	                        begin //abnormal
168	                        filter_state <= ABNORMAL_STATE;
169	                        end
170	                    end
171	                else 
172	                    begin
173	                    allow_rx_dma_to_ps_reg <= allow_rx_dma_to_ps_reg;
174	                    high_priority_discard_reg<=high_priority_discard_reg;
175	                    filter_state <= filter_state;
176	                    filter_state_pre <= filter_state_pre;
177	                    end
178	                end
179	
180	            WAIT_FOR_ADDR1: 
181	                begin
182	                block_rx_dma_to_ps_valid <= block_rx_dma_to_ps_valid;
183	                allow_rx_dma_to_ps_reg <= allow_rx_dma_to_ps_reg;
184	                high_priority_discard_reg<=high_priority_discard_reg;
185	                abnormal_flag<=abnormal_flag;
186	                if (addr1_valid) 
187	                    begin
188	                    filter_state_pre <= filter_state;
189	                    if (FC_tofrom_ds==2'b10) 
190	                        begin
191	                        filter_bssid <= addr1;
192	                        filter_bssid_valid<=1;
193	                        end
194	                    else 
195	                        begin
196	                        filter_bssid<=filter_bssid;
197	                        filter_bssid_valid<=filter_bssid_valid;
198	                        end
199	
200	                    if (is_ctrlwrapper || is_ack) 
201	                        begin
202	                        filter_state <= FILTER_ACTION;
203	                        end
204	                    else if (signal_len>=20) 
205	                        begin
206	                        filter_state <= WAIT_FOR_ADDR2;
207	                        end
208	                    else 
209	                        begin // between 14 and 20. abnormal
210	                        filter_state <= ABNORMAL_STATE;
211	                        end
212	                    end
213	                else 
214	                    begin
215	                    filter_state <= filter_state;
216	                    filter_state_pre <= filter_state_pre;
217	                    filter_bssid<=filter_bssid;
218	                    filter_bssid_valid<=filter_bssid_valid;
219	                    end
220	                end
221	
222	            WAIT_FOR_ADDR2:
223	                begin
224	                block_rx_dma_to_ps_valid <= block_rx_dma_to_ps_valid;
225	                allow_rx_dma_to_ps_reg <= allow_rx_dma_to_ps_reg;
226	                high_priority_discard_reg<=high_priority_discard_reg;
227	                abnormal_flag<=abnormal_flag;
228	                if (addr2_valid) 
229	                    begin
230	                    filter_state_pre <= filter_state;
231	                    if (FC_tofrom_ds==2'b01) 
232	                        begin
233	                        filter_bssid <= addr2;
234	                        filter_bssid_valid<=1;
235	                        end
236	                    else 
237	                        begin
238	                        filter_bssid<=filter_bssid;
239	                        filter_bssid_valid<=filter_bssid_valid;
240	                        end
241	
242	                    if (is_rts || is_pspoll || is_cfend || is_cfend_cfack || is_blkackreq || is_blkack) 
243	                        begin
244	                        filter_state <= FILTER_ACTION;
245	                        end
246	                    else if (signal_len>=26) 
247	                        begin
248	                        filter_state <= WAIT_FOR_ADDR3;
249	                        end
250	                    else 
251	                        begin // between 20 and 26. abnormal
252	                        filter_state <= ABNORMAL_STATE;
253	                        end
254	                    end
255	                else 
256	                    begin
257	                    filter_state <= filter_state;
258	                    filter_state_pre <= filter_state_pre;
259	                    filter_bssid<=filter_bssid;
260	                    filter_bssid_valid<=filter_bssid_valid;
261	                    end
262	                end
263	
264	            WAIT_FOR_ADDR3:
265	                begin
266	                block_rx_dma_to_ps_valid <= block_rx_dma_to_ps_valid;
267	                allow_rx_dma_to_ps_reg <= allow_rx_dma_to_ps_reg;
268	                high_priority_discard_reg<=high_priority_discard_reg;
269	                abnormal_flag<=abnormal_flag;
270	                if (addr3_valid) 
271	                    begin
272	                    filter_state_pre <= filter_state;
273	                    filter_state <= FILTER_ACTION;
274	                    if (FC_tofrom_ds==2'b00) 
275	                        begin
276	                        filter_bssid <= addr3;
277	                        filter_bssid_valid<=1;
278	                        end
279	                    else 
280	                        begin
281	                        filter_bssid<=filter_bssid;
282	                        filter_bssid_valid<=filter_bssid_valid;
283	                        end
284	                    end
285	                else 
286	                    begin
287	                    filter_state <= filter_state;
288	                    filter_state_pre <= filter_state_pre;
289	                    filter_bssid<=filter_bssid;
290	                    filter_bssid_valid<=filter_bssid_valid;
291	                    end
292	                end
293	
294	            FILTER_ACTION:
295	                begin
296	                block_rx_dma_to_ps_valid <= 1;
297	
298	                allow_rx_dma_to_ps_reg[3:2] <= allow_rx_dma_to_ps_reg[3:2];
299	                allow_rx_dma_to_ps_reg[0] <= allow_rx_dma_to_ps_reg[0];
300	
301	                high_priority_discard_reg[3:2]<=high_priority_discard_reg[3:2];
302	                high_priority_discard_reg[0]<=high_priority_discard_reg[0];
303	
304	                if ( (FIF_ALLMULTI&filter_cfg) && ( (addr1[23:0]==24'H5E0001) || (addr1[15:0]==16'H3333) ) ) // pass all multicast frame like 01:00:5E:xx:xx:xx and 33:33:xx:xx:xx:xx to ARM
305	                    begin
306	                    allow_rx_dma_to_ps_reg[1] <= 1;
307	                    high_priority_discard_reg[1] <= high_priority_discard_reg[1];
308	                    end
309	                else
310	                    begin
311	                    allow_rx_dma_to_ps_reg[1] <= allow_rx_dma_to_ps_reg[1];
312	                    if ( (FIF_ALLMULTI&filter_cfg)==0 && ( (addr1[23:0]==24'H5E0001) || (addr1[15:0]==16'H3333) ) )
313	                        high_priority_discard_reg[1] <= 1;
314	                    else
315	                        high_priority_discard_reg[1] <= high_priority_discard_reg[1];
316	                    end
317	
318	                if ( (FIF_BCN_PRBRESP_PROMISC&filter_cfg) && ( ( is_beacon || is_proberesp ) ) ) // pass all beacon and probe response (even they are not for our ssid) to ARM
319	                    begin
320	                    allow_rx_dma_to_ps_reg[4] <= 1;
321	                    high_priority_discard_reg[4] <=high_priority_discard_reg[4];
322	                    end
323	                else
324	                    begin
325	                    allow_rx_dma_to_ps_reg[4] <= allow_rx_dma_to_ps_reg[4];
326	                    if ( (FIF_BCN_PRBRESP_PROMISC&filter_cfg)==0 && ( ( is_beacon || is_proberesp ) ) && (filter_bssid_valid==1 && filter_bssid!=self_bssid) )
327	                        high_priority_discard_reg[4] <= 1;
328	                    else
329	                        high_priority_discard_reg[4] <=high_priority_discard_reg[4];
330	                    end
331	                
332	                if ( (FIF_CONTROL&filter_cfg) && ( (addr1==self_mac_addr) && ( except_pspoll ) ) ) // pass control frames (except for PS Poll) addressed to this station to ARM
333	                    begin
334	                    allow_rx_dma_to_ps_reg[5] <= 1;
335	                    high_priority_discard_reg[5] <= high_priority_discard_reg[5];
336	                    end
337	                else
338	                    begin
339	                    allow_rx_dma_to_ps_reg[5] <= allow_rx_dma_to_ps_reg[5];
340	                    if ( (FIF_CONTROL&filter_cfg)==0 && ( except_pspoll ) )
341	                        high_priority_discard_reg[5] <= 1;
342	                    else
343	                        high_priority_discard_reg[5] <= high_priority_discard_reg[5];
344	                    end
345	
346	                if ( (FIF_OTHER_BSS&filter_cfg) && ( (filter_bssid_valid==1 && filter_bssid!=self_bssid) ) ) // pass frames destined to other BSSes to ARM
347	                    begin
348	                    allow_rx_dma_to_ps_reg[6] <= 1;
349	                    high_priority_discard_reg[6] <= high_priority_discard_reg[6];
350	                    end
351	                else
352	                    begin
353	                    allow_rx_dma_to_ps_reg[6] <= allow_rx_dma_to_ps_reg[6];
354	                    if ( (FIF_OTHER_BSS&filter_cfg)==0 && ( (filter_bssid_valid==1 && filter_bssid!=self_bssid) ) )
355	                        high_priority_discard_reg[6] <= 1;
356	                    else
357	                        high_priority_discard_reg[6] <= high_priority_discard_reg[6];
358	                    end
359	
360	                if ( (FIF_PSPOLL&filter_cfg) && ( is_pspoll ) ) // pass PS Poll frames to ARM
361	                    begin
362	                    allow_rx_dma_to_ps_reg[7] <= 1;
363	                    high_priority_discard_reg[7] <= high_priority_discard_reg[7];
364	                    end
365	                else
366	                    begin
367	                    allow_rx_dma_to_ps_reg[7] <= allow_rx_dma_to_ps_reg[7];
368	                    if ( (FIF_PSPOLL&filter_cfg)==0 && ( is_pspoll ) )
369	                        high_priority_discard_reg[7] <= 1;
370	                    else
371	                        high_priority_discard_reg[7] <= high_priority_discard_reg[7];
372	                    end
373	
374	                if ( (FIF_PROBE_REQ&filter_cfg) && ( is_probereq ) ) // pass probe request frames to ARM
375	                    begin
376	                    allow_rx_dma_to_ps_reg[8] <= 1;
377	                    high_priority_discard_reg[8] <= high_priority_discard_reg[8];
378	                    end
379	                else
380	                    begin
381	                    allow_rx_dma_to_ps_reg[8] <= allow_rx_dma_to_ps_reg[8];
382	                    if ( (FIF_PROBE_REQ&filter_cfg)==0 && ( is_probereq ) )
383	                        high_priority_discard_reg[8] <= 1;
384	                    else
385	                        high_priority_discard_reg[8] <= high_priority_discard_reg[8];
386	                    end
387	
388	                if ( (UNICAST_FOR_US&filter_cfg) && (addr1==self_mac_addr) ) // pass unicast for us to ARM
389	                    allow_rx_dma_to_ps_reg[9] <= 1;
390	                else
391	                    allow_rx_dma_to_ps_reg[9] <= allow_rx_dma_to_ps_reg[9];
392	
393	                if ( (BROADCAST_ALL_ONE&filter_cfg) && (addr1==48'HFFFFFFFFFFFF) ) // pass all 1 target addr packet to ARM
394	                    allow_rx_dma_to_ps_reg[10] <= 1;
395	                else
396	                    allow_rx_dma_to_ps_reg[10] <= allow_rx_dma_to_ps_reg[10];
397	
398	                if ( (BROADCAST_ALL_ZERO&filter_cfg) && (addr1==48'H000000000000) ) // pass all 0 target addr packet to ARM
399	                    allow_rx_dma_to_ps_reg[11] <= 1;
400	                else
401	                    allow_rx_dma_to_ps_reg[11] <= allow_rx_dma_to_ps_reg[11];
402	
403	                if ( (MY_BEACON&filter_cfg) && ( (filter_bssid_valid==1 && filter_bssid==self_bssid) && is_beacon ) ) // pass only beacon in my ssid to ARM
404	                    allow_rx_dma_to_ps_reg[12] <= 1;
405	                else
406	                    allow_rx_dma_to_ps_reg[12] <= allow_rx_dma_to_ps_reg[12];
407	
408	                if ( MONITOR_ALL&filter_cfg ) // pass all to ARM
409	                    allow_rx_dma_to_ps_reg[13] <= 1;
410	                else
411	                    allow_rx_dma_to_ps_reg[13] <= allow_rx_dma_to_ps_reg[13];
412	
413	                filter_bssid <= filter_bssid;
414	                filter_bssid_valid <= filter_bssid_valid;
415	                filter_state <= FILTER_IDLE;
416	                filter_state_pre <= filter_state;
417	                abnormal_flag <= abnormal_flag;
418	                end
419	
420	            ABNORMAL_STATE:
421	                begin
422	                block_rx_dma_to_ps_valid <= 1;
423	                allow_rx_dma_to_ps_reg <= 0;
424	                high_priority_discard_reg<=9'h1FF;
425	                filter_bssid <= filter_bssid;
426	                filter_bssid_valid <= filter_bssid_valid;
427	                filter_state <= FILTER_IDLE;
428	                filter_state_pre <= filter_state;
429	                abnormal_flag <= 1;
430	                end
431	        endcase                                                               
432	    end
433	
434	`ifdef RTLXXXXXXXXX
435	    //reg fcs_valid_delay;
436	    //reg fcs_invalid_delay;
437	    //reg block_rx_dma_to_ps_delay;
438	    
439	    always @( posedge clk )
440	    if ( rstn == 1'b0 || pkt_header_valid_strobe )
441	        begin
442	        block_rx_dma_to_ps <= 0;
443	        end
444	    else
445	        begin
446	        if ( FC_DI_valid &&      ( ((FC_tofrom_ds==FC_tofrom_ds_filter0)&&FC_tofrom_ds_filter0_enable) || 
447	                                   ((FC_tofrom_ds==FC_tofrom_ds_filter1)&&FC_tofrom_ds_filter1_enable) || 
448	                                   ((FC_tofrom_ds==FC_tofrom_ds_filter2)&&FC_tofrom_ds_filter2_enable)    ) )
449	            begin
450	            block_rx_dma_to_ps<=1;
451	            end
452	        else if ( FC_DI_valid && ( (( is_beacon||is_proberesp )&&FC_BCN_PRBRESP_filter_enable) || //beacon and probe response
453	                                   (( except_pspoll )&&FC_CONTROL_filter_enable)     || //control frame except for PS Poll
454	                                   (( is_pspoll )&&FC_PSPOLL_filter_enable)      || //PS POLL frame
455	                                   (( is_probereq )&&FC_PROBE_REQ_filter_enable)         //PROBE_REQ
456	                                                                        ) )
457	            begin
458	            block_rx_dma_to_ps<=1;
459	            end
460	        else if ( dst_addr_valid && ( (dst_addr!=48'HFFFFFFFFFFFF || (!special_addr_filter0_enable)) && 
461	                                      (dst_addr!=48'H000000000000 || (!special_addr_filter1_enable)) && 
462	                                      (dst_addr!=self_mac_addr    || (!dst_addr_filter_enable)) ) )
463	            begin
464	            block_rx_dma_to_ps<=1;
465	            end
466	        else if ( bssid_valid && ((bssid!=self_bssid)&&bssid_filter_enable) )
467	            begin
468	            block_rx_dma_to_ps<=1;
469	            end
470	        //else if (fcs_valid_delay||fcs_invalid_delay)
471	        else if (pkt_header_valid_strobe)
472	            begin
473	            block_rx_dma_to_ps<=0;
474	            end
475	        
476	//        if ( (block_rx_dma_to_ps_delay==0) && (block_rx_dma_to_ps==1) )
477	//            begin
478	//            filter_count = filter_count + 1;
479	//            end
480	        end
481	`endif
482	
483		endmodule
